[
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 491,
    "severity": "medium",
    "description": "Error message for ephemeral validation failures says 'sensitive' instead of 'ephemeral'. When a variable validation rule's error message expression refers to an ephemeral value, the error message shown to the user incorrectly states that a 'sensitive value' was involved, contradicting the Diagnostic summary and detail which correctly reference 'ephemeral values'. This creates user confusion about what actually went wrong.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -488,7 +488,7 @@ func evalVariableValidation(validation *configs.CheckRule, hclCtx *hcl.EvalCont
 				EvalContext: hclCtx,
 			})
 			errorMessage = "The error message included a sensitive value, so it will not be displayed."
-		} else {
+			errorMessage = "The error message included an ephemeral value, so it will not be displayed."
+		} else {
 			errorMessage = strings.TrimSpace(errorValue.AsString())
 		}
"
  },
  {
    "file": "internal/terraform/context_apply.go",
    "line": 153,
    "severity": "high",
    "description": "Hook return values are ignored during import processing. The code calls PreApplyImport and PostApplyImport on hooks but completely ignores their return values. Per the Hook interface contract, these methods can return HookActionHalt (which should immediately stop processing) or errors, but neither is checked. This violates the hook contract and could allow hooks that attempt to halt the import operation to be silently ignored.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -149,9 +149,17 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts
 			for _, h := range c.hooks {
 				// In future, we may need to call PostApplyImport separately elsewhere in the apply
 				// operation. For now, though, we'll call Pre and Post hooks together.
-				h.PreApplyImport(hookResourceID, *rc.Importing)
-				h.PostApplyImport(hookResourceID, *rc.Importing)
+				action, _ := h.PreApplyImport(hookResourceID, *rc.Importing)
+				if action == HookActionHalt {
+					break
+				}
+				action, _ = h.PostApplyImport(hookResourceID, *rc.Importing)
+				if action == HookActionHalt {
+					break
+				}
 			}
 		}
 	}
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 875,
    "severity": "critical",
    "description": "Array size calculation doesn't account for sparse instance keys in ephemeral resources. In getEphemeralResource, when handling IntKeyType (count), the code creates an array with size len(keys) then tries to index it with int(key) values. If instance keys are sparse (e.g., [0, 2, 4]), this causes array index out of bounds panic. The GetResource function (lines 720-754) correctly handles this by calculating the maximum index first. This bug prevents any ephemeral resource with count where not all instances are active from being evaluated.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -870,14 +870,28 @@ func (d *evaluationStateData) getEphemeralResource(addr addrs.Resource, rng tfd
 	return instVal, diags
 	}

 	switch keyType {
 	case addrs.NoKeyType:
 		// For "no key" we're returning just a single object representing
 		// the single instance of this resource.
 		instVal, moreDiags := getInstValue(absAddr.Instance(addrs.NoKey))
 		diags = diags.Append(moreDiags)
 		return instVal, diags
 	case addrs.IntKeyType:
 		// For integer keys we're returning a tuple-typed value whose
 		// indices are the keys.
-		elems := make([]cty.Value, len(keys))
+		// First, find the maximum index to determine the length of the tuple.
+		length := 0
+		for _, key := range keys {
+			intKey := int(key.(addrs.IntKey))
+			if intKey >= length {
+				length = intKey + 1
+			}
+		}
+		elems := make([]cty.Value, length)
 		for _, key := range keys {
 			idx := int(key.(addrs.IntKey))
 			instAddr := absAddr.Instance(key)
 			instVal, moreDiags := getInstValue(instAddr)
 			diags = diags.Append(moreDiags)
 			elems[idx] = instVal
+		}
+		// Fill in any missing values with ephemeral dynamic values
+		for i := range elems {
+			if elems[i] == cty.NilVal {
+				elems[i] = cty.DynamicVal.Mark(marks.Ephemeral)
+			}
 		}
 		return cty.TupleVal(elems), diags
"
  }
]

